/**
 * Tests for `renderBrowse` — the browse-result renderer (table headers, rows,
 * columns, in-app navigation, the Actions column with Download/Delete/Move/Copy
 * + their error surfacing, the breadcrumb, and the status footer).
 *
 * Split out of the former `src/app.test.ts` monolith (task-29). Shared
 * fixtures, DOM scaffolding, and the per-test fetch stub come from
 * `./test-helpers`.
 *
 * Environment: the project-default `happy-dom` (these tests need a DOM).
 *
 * Contract decisions encoded here (carried over from the monolith):
 *  - In-app navigation (directory name links, the ".." parent row, breadcrumb
 *    segments) is verified by asserting on `window.location.hash` after a
 *    click — robust to either a `navigate(...)` call OR an
 *    `<a href="#...">` (happy-dom follows hash-fragment href clicks).
 *  - The results table uses a `<thead>` (header `<th>` row) and a `<tbody>`
 *    (data `<td>` rows). Column order for browse is
 *    `Name | Size | Modified | Actions`.
 *  - `renderBrowse` operates against the DOM context `startApp` establishes
 *    (module-level element refs), so every test calls `setup()`/`setupCleared()`
 *    first.
 */
import { describe, it, expect, vi, beforeEach } from 'vitest';
import { renderBrowse } from '../app';
import { toBrowseHash } from '../router';
import { formatBytes, normalizeRelativePath } from '../format';
import { mockResponse } from '../test-utils/mock-response';
import {
  setup,
  setupCleared,
  flush,
  browseResult,
  fileEntry,
  dataRows,
  rowByName,
  cellsOf,
  clickNameLink,
  buttonsByText,
  fetchMock,
  ISO_FMT,
  installAppTestLifecycle,
} from './test-helpers';

installAppTestLifecycle();

/* ===========================================================================
 * Accessible-name / visible-text helpers
 *
 * Used to assert the Actions column header contract: it must announce
 * "Actions" to screen readers while remaining visually blank. Two acceptable
 * implementations both satisfy that contract:
 *   - `<th aria-label="Actions"></th>` (aria-label is the accessible name;
 *     textContent stays empty), or
 *   - `<th><span class="visually-hidden">Actions</span></th>` (the hidden
 *     span's text is the accessible name; nothing renders visually).
 * The helpers below let the tests pin the *contract* (accessible name +
 * visually blank) rather than a single mechanism, so they pass under either.
 * ========================================================================= */

/**
 * The accessible name of an element per WAI-ARIA name computation: `aria-label`
 * first, then `aria-labelledby` (resolved against the document), then the
 * element's own text content. Mirrors what a screen reader announces.
 */
function accessibleName(el: Element): string {
  const ariaLabel = el.getAttribute('aria-label');
  if (ariaLabel !== null && ariaLabel.trim() !== '') {
    return ariaLabel.trim();
  }
  const labelledBy = el.getAttribute('aria-labelledby');
  if (labelledBy) {
    return labelledBy
      .trim()
      .split(/\s+/)
      .map((id) => (document.getElementById(id)?.textContent ?? '').trim())
      .join(' ')
      .trim();
  }
  return (el.textContent ?? '').trim();
}

/**
 * The text an element renders for a SIGHTED user: its textContent with any
 * `.visually-hidden` descendants removed. A visually-blank header is one whose
 * `visibleText` is `''` — whether it is an empty `<th>` with an `aria-label`,
 * or a `<th>` whose only text lives inside a `.visually-hidden` span.
 */
function visibleText(el: Element): string {
  const clone = el.cloneNode(true) as Element;
  for (const hidden of Array.from(clone.querySelectorAll('.visually-hidden'))) {
    hidden.remove();
  }
  return (clone.textContent ?? '').trim();
}

/* ===========================================================================
 * renderBrowse — table, rows, columns, navigation, actions
 * ========================================================================= */
describe('renderBrowse', () => {
  it('builds a table with visible headers Name | Size | Modified | (blank Actions)', async () => {
    const { results } = await setupCleared();
    renderBrowse(browseResult({ path: 'docs', entries: [] }));

    const table = results.querySelector('table');
    expect(table).toBeTruthy();
    const headers = Array.from(table!.querySelectorAll('thead th')).map((h) => visibleText(h));
    // The Actions column shows no VISIBLE header label (the per-row controls
    // are icon-only "⋮" menus), so its rendered text is blank — but all four
    // <th> remain so the header column count lines up with the four <td> per
    // body row. The Actions header still carries an accessible name for screen
    // readers; that is pinned in the "Actions column header accessibility"
    // suite below. `visibleText` ignores `.visually-hidden` text, so this is
    // agnostic to whether the label is an `aria-label` or a hidden span.
    expect(headers).toEqual(['Name', 'Size', 'Modified', '']);
  });

  it('tags the browse table with the browse-table class alongside results-table', async () => {
    const { results } = await setupCleared();
    renderBrowse(browseResult({ path: 'docs', entries: [] }));

    const table = results.querySelector('table')!;
    expect(table.classList.contains('results-table')).toBe(true);
    expect(table.classList.contains('browse-table')).toBe(true);
  });

  it('keeps the Actions column header th visually blank but present (four header cells)', async () => {
    const { results } = await setupCleared();
    renderBrowse(browseResult({ path: 'docs', entries: [] }));

    const headers = Array.from(results.querySelector('table')!.querySelectorAll('thead th'));
    expect(headers).toHaveLength(4);
    // Visually blank (no rendered label) — but NOT unlabeled: it carries an
    // accessible name (asserted in the suite below). `visibleText` ignores
    // `.visually-hidden` text, so this passes whether the label is an
    // `aria-label` (empty textContent) or a `.visually-hidden` span.
    expect(visibleText(headers[3])).toBe('');
  });

  describe('Actions column header accessibility', () => {
    /* The per-row controls in the Actions column are icon-only "⋮" menus, so
       the column header intentionally shows no VISIBLE label. But a header
       with neither visible text nor an accessible name is invisible to screen
       readers: a user navigating the table by column header could not tell
       what the fourth column contains. The header must therefore be *visually
       blank* yet still announce "Actions" to assistive tech. The tests below
       pin that contract (via `accessibleName` / `visibleText`), independent of
       whether it is implemented as `aria-label="Actions"` or a
       `.visually-hidden` span. */

    it('the Actions header announces "Actions" as its accessible name', async () => {
      const { results } = await setupCleared();
      renderBrowse(browseResult({ path: 'docs', entries: [] }));

      const headers = Array.from(results.querySelector('table')!.querySelectorAll('thead th'));
      expect(headers).toHaveLength(4);
      expect(accessibleName(headers[3])).toBe('Actions');
    });

    it('the Actions header renders no visible label text (visually blank)', async () => {
      const { results } = await setupCleared();
      renderBrowse(browseResult({ path: 'docs', entries: [] }));

      const headers = Array.from(results.querySelector('table')!.querySelectorAll('thead th'));
      expect(visibleText(headers[3])).toBe('');
    });

    it('labels ONLY the Actions column — the other three headers keep their visible labels', async () => {
      const { results } = await setupCleared();
      renderBrowse(browseResult({ path: 'docs', entries: [] }));

      const headers = Array.from(results.querySelector('table')!.querySelectorAll('thead th'));
      // Accessible names: Name / Size / Modified for the first three (from
      // their visible text), Actions for the fourth.
      expect(accessibleName(headers[0])).toBe('Name');
      expect(accessibleName(headers[1])).toBe('Size');
      expect(accessibleName(headers[2])).toBe('Modified');
      expect(accessibleName(headers[3])).toBe('Actions');
      // Visible labels for the first three are unchanged (regression guard:
      // the fix must not blank out or relabel the other headers).
      expect(visibleText(headers[0])).toBe('Name');
      expect(visibleText(headers[1])).toBe('Size');
      expect(visibleText(headers[2])).toBe('Modified');
    });

    it('keeps the accessible label after a re-render into the same results element', async () => {
      const { results } = await setupCleared();
      renderBrowse(browseResult({ path: 'docs', entries: [] }));
      // Simulate the re-render that follows a Delete/Move/Copy mutation:
      // .results is cleared and renderBrowse rebuilds the table. The label
      // must be re-applied, not dropped by a one-shot side effect.
      results.innerHTML = '';
      renderBrowse(browseResult({ path: 'other', entries: [] }));

      const headers = Array.from(results.querySelector('table')!.querySelectorAll('thead th'));
      expect(accessibleName(headers[3])).toBe('Actions');
      expect(visibleText(headers[3])).toBe('');
    });

    it('keeps the accessible label when the table also has body rows and a ".." parent row', async () => {
      // Body rows (and the ".." parent row) must not change the header's
      // accessible name: the label is a property of the <thead>, independent
      // of how many <tbody> rows are present.
      const { results } = await setupCleared();
      renderBrowse(
        browseResult({
          path: 'docs/sub',
          parent: 'docs',
          entries: [fileEntry({ name: 'a.txt', isDirectory: false, size: 5 })],
        }),
      );

      const headers = Array.from(results.querySelector('table')!.querySelectorAll('thead th'));
      expect(accessibleName(headers[3])).toBe('Actions');
      expect(visibleText(headers[3])).toBe('');
    });
  });

  it('keeps four td per body row so column counts line up with the header', async () => {
    const entries = [
      fileEntry({ name: 'a.txt', isDirectory: false, size: 10 }),
      fileEntry({ name: 'sub', isDirectory: true }),
    ];
    const { results } = await setupCleared();
    renderBrowse(browseResult({ path: 'docs', entries }));

    for (const row of dataRows(results.querySelector('table')!)) {
      expect(cellsOf(row)).toHaveLength(4);
    }
  });

  it('renders one data row per entry when there is no parent', async () => {
    const entries = [
      fileEntry({ name: 'a.txt', isDirectory: false, size: 10 }),
      fileEntry({ name: 'sub', isDirectory: true }),
    ];
    const { results } = await setupCleared();
    renderBrowse(browseResult({ path: 'docs', entries }));

    expect(dataRows(results.querySelector('table')!)).toHaveLength(2);
  });

  it('prepends a ".." parent row only when result.parent is not null', async () => {
    const entry = fileEntry({ name: 'a.txt' });
    const { results } = await setupCleared();

    renderBrowse(browseResult({ path: 'docs/sub', parent: 'docs', entries: [entry] }));
    const tableWithParent = results.querySelector('table')!;
    const rowsWithParent = dataRows(tableWithParent);
    expect(rowsWithParent).toHaveLength(2);
    expect(cellsOf(rowsWithParent[0])[0].textContent?.trim()).toBe('..');

    results.innerHTML = '';
    renderBrowse(browseResult({ path: 'docs', parent: null, entries: [entry] }));
    const tableNoParent = results.querySelector('table')!;
    expect(dataRows(tableNoParent)).toHaveLength(1);
    expect(cellsOf(dataRows(tableNoParent)[0])[0].textContent?.trim()).toBe('a.txt');
  });

  it('clicking the ".." row navigates to toBrowseHash(result.parent)', async () => {
    const { results } = await setupCleared();
    renderBrowse(browseResult({ path: 'docs/sub', parent: 'docs', entries: [] }));
    const parentRow = rowByName(results.querySelector('table')!, '..')!;

    clickNameLink(parentRow);

    expect(window.location.hash).toBe(toBrowseHash('docs'));
  });

  describe('directory rows', () => {
    it('renders the name and an em-dash size, and clicking the name navigates into the folder', async () => {
      const dir = fileEntry({ name: 'sub', path: 'docs/sub', isDirectory: true });
      const { results } = await setupCleared();
      renderBrowse(browseResult({ path: 'docs', entries: [dir] }));

      const row = rowByName(results.querySelector('table')!, 'sub')!;
      const [nameCell, sizeCell] = cellsOf(row);
      expect(nameCell.textContent?.trim()).toBe('sub');
      expect(sizeCell.textContent?.trim()).toBe('—');

      clickNameLink(row);
      expect(window.location.hash).toBe(toBrowseHash('docs/sub'));
    });
  });

  describe('file rows', () => {
    const file = fileEntry({ name: 'a.txt', path: 'docs/a.txt', isDirectory: false, size: 1536 });

    it('renders the name as plain text (no navigation link)', async () => {
      const { results } = await setupCleared();
      renderBrowse(browseResult({ path: 'docs', entries: [file] }));
      const row = rowByName(results.querySelector('table')!, 'a.txt')!;
      const [nameCell] = cellsOf(row);
      expect(nameCell.textContent?.trim()).toBe('a.txt');
      expect(nameCell.querySelector('a, button')).toBeNull();
    });

    it('shows formatBytes(size) for the Size column', async () => {
      const { results } = await setupCleared();
      renderBrowse(browseResult({ path: 'docs', entries: [file] }));
      const row = rowByName(results.querySelector('table')!, 'a.txt')!;
      const sizeCell = cellsOf(row)[1];
      expect(sizeCell.textContent?.trim()).toBe(formatBytes(1536));
      expect(sizeCell.textContent?.trim()).toBe('1.5 KB');
    });

    it('shows formatDate(lastModified) for the Modified column', async () => {
      const { results } = await setupCleared();
      renderBrowse(browseResult({ path: 'docs', entries: [file] }));
      const row = rowByName(results.querySelector('table')!, 'a.txt')!;
      const modifiedCell = cellsOf(row)[2];
      expect(modifiedCell.textContent?.trim()).toBe(ISO_FMT);
    });

    it('escapes names via textContent (no HTML injection)', async () => {
      const evil = fileEntry({
        name: '<img src=x onerror=alert(1)>',
        path: 'docs/x',
        isDirectory: false,
      });
      const { results } = await setupCleared();
      renderBrowse(browseResult({ path: 'docs', entries: [evil] }));

      const nameCell = cellsOf(rowByName(results.querySelector('table')!, evil.name)!)[0];
      // The literal markup must NOT have been parsed as HTML.
      expect(results.querySelector('img')).toBeNull();
      expect(nameCell.textContent).toContain('<img');
    });
  });

  describe('Actions column', () => {
