        return parseFloat(styleValue);
      }
      /** Open the row's menu at (x, y) by dispatching a right-click on the row. */
      function openViaContext(row: Element, x: number, y: number): void {
        row.dispatchEvent(
          new MouseEvent('contextmenu', {
            cancelable: true,
            bubbles: true,
            clientX: x,
            clientY: y,
          }),
        );
      }

